// Query depth limiting middleware
function depthLimit(maxDepth) {
  return (req, res, next) => {
    const query = req.body && req.body.query;
    if (!query) {
      return next();
    }

    let depth = 0;
    let maxFound = 0;
    for (const char of query) {
      if (char === '{') {
        depth++;
        if (depth > maxFound) {
          maxFound = depth;
        }
      } else if (char === '}') {
        depth--;
      }
    }

    if (maxFound > maxDepth) {
      res.status(400).json({
        errors: [
          {
            message: `Query depth of ${maxFound} exceeds maximum allowed depth of ${maxDepth}.`,
          },
        ],
      });
      return;
    }

    next();
  };
}

// Query complexity / size limiting middleware
function querySizeLimit(maxLength) {
  return (req, res, next) => {
    const query = req.body && req.body.query;
    if (query && query.length > maxLength) {
      res.status(400).json({
        errors: [
          {
            message: `Query length of ${query.length} exceeds maximum allowed length of ${maxLength}.`,
          },
        ],
      });
      return;
    }
    next();
  };
}

